const base = 'http://prometheus:9090/api/v1/query';

async function query(expr) {
  const res = await fetch(`${base}?query=${encodeURIComponent(expr)}`);
  const data = await res.json();
  const first = data?.data?.result?.[0]?.value?.[1];
  const n = Number(first);
  return Number.isFinite(n) ? n : null;
}

const cpu = await query('100 - (avg(irate(node_cpu_seconds_total{mode="idle"}[5m])) * 100)');
const mem = await query('(1 - (node_memory_MemAvailable_bytes / node_memory_MemTotal_bytes)) * 100');
const swap = await query('(1 - (node_memory_SwapFree_bytes / node_memory_SwapTotal_bytes)) * 100');
const diskFree = await query('(node_filesystem_avail_bytes{mountpoint="/",fstype!~"tmpfs|overlay"} / node_filesystem_size_bytes{mountpoint="/",fstype!~"tmpfs|overlay"}) * 100');
const downCount = await query('count(up == 0)');
const probeFail = await query('count(probe_success == 0)');

const now = new Date();
const isSunday = now.getDay() === 0;
const health = ((downCount ?? 0) > 0 || (probeFail ?? 0) > 0 || (swap ?? 0) > 80) ? 'ALERTA' : 'OK';

const brief = [
  `RESUMEN DIARIO [${health}]`,
  `Hora: ${now.toISOString()}`,
  `CPU ${cpu?.toFixed(1) ?? 'n/a'}% | RAM ${mem?.toFixed(1) ?? 'n/a'}% | Swap ${swap?.toFixed(1) ?? 'n/a'}%`,
  `Disk libre /: ${diskFree?.toFixed(1) ?? 'n/a'}%`,
  `Servicios down: ${Number(downCount ?? 0).toFixed(0)} | Probes KO: ${Number(probeFail ?? 0).toFixed(0)}`
].join('\n');

const detailed = [
  `PUNTO DE SITUACION SEMANAL [${health}]`,
  `Hora: ${now.toISOString()}`,
  '',
  `- CPU host: ${cpu?.toFixed(2) ?? 'n/a'}%`,
  `- RAM usada: ${mem?.toFixed(2) ?? 'n/a'}%`,
  `- Swap usada: ${swap?.toFixed(2) ?? 'n/a'}%`,
  `- Disco libre /: ${diskFree?.toFixed(2) ?? 'n/a'}%`,
  `- Servicios no scrapeables: ${Number(downCount ?? 0).toFixed(0)}`,
  `- Probes HTTP en fallo: ${Number(probeFail ?? 0).toFixed(0)}`,
  '',
  'Accion recomendada:',
  health === 'OK' ? '- Sin accion urgente. Mantener vigilancia.' : '- Revisar alertas activas en Grafana/Alertmanager y actuar segun severidad.'
].join('\n');

return [{ json: { message: isSunday ? detailed : brief } }];
